patch:
--- a/parity_checker.vhd
+++ b/parity_checker.vhd
@@ -1,18 +1,18 @@
 library ieee;
 use ieee.std_logic_1164.all;

 entity parity_checker is
   port (
     data_in : in std_logic_vector(15 downto 0);
     parity_bit : in std_logic;
     error_flag : out std_logic
   );
 end parity_checker;

 architecture rtl of parity_checker is
 begin
-  process(data_in)
+  process(data_in, parity_bit)
     variable xor_result : std_logic;
   begin
     xor_result := '0';
     for i in 0 to 15 loop
       xor_result := xor_result xor data_in(i);
     end loop;
     error_flag <= xor_result xor parity_bit;
   end process;

 end rtl;

